/// <summary>
/// Extension of the <c>PrintMgmtReportFormatPopulator</c> class for the ETGSPAIN model.
/// </summary>
[ExtensionOf(classStr(PrintMgmtReportFormatPopulator))]
public final class PrintMgmtReportFormatPopulatorETGSPAIN_Extension
{        
}

Method.Source:
/// <summary>
/// Extension of the <c>addDocuments</c> method.
/// </summary>
protected void addDocuments()
{        
    this.ETGSPAINaddAgreementCustomDocuments();
    this.ETGSPAINaddSalesConfirmCustomDocuments();
    //this.ETGSPAINaddSalesInvoiceCustomDocuments();

    next addDocuments();
}

/// <summary>
/// Method to add report extensions for Purchase/Sales Agreements in ETGSPAIN.
/// </summary>
private void ETGSPAINaddAgreementCustomDocuments()
{
    #PrintMgmtSetup
    this.addOther(PrintMgmtDocumentType::SalesAgreementConfirmation, ssrsReportStr(ETGSPAINAgreementConfirmation, Report), ssrsReportStr(ETGSPAINAgreementConfirmation, Report), #NoCountryRegionId);
    this.addOther(PrintMgmtDocumentType::PurchAgreementConfirmation, ssrsReportStr(ETGSPAINAgreementConfirmation, Report), ssrsReportStr(ETGSPAINAgreementConfirmation, Report), #NoCountryRegionId);
}

    /// <summary>
    /// Method to add report extensions for Sales Order Confirmations in ETGSPAIN.
    /// </summary>
    private void ETGSPAINaddSalesConfirmCustomDocuments()
    {
        #PrintMgmtSetup
        this.addOther(PrintMgmtDocumentType::SalesOrderConfirmation, ssrsReportStr(ETGSPAINSalesConfirm, Report), ssrsReportStr(ETGSPAINSalesConfirm, Report), #NoCountryRegionId);        
    }

